import * as THREE from 'three';
import { CONFIG } from './config';
import { createScene } from './scene/createScene';
import { createRenderer } from './scene/createRenderer';
import { InputManager } from './systems/InputManager';
import { intersects } from './systems/CollisionSystem';
import { AudioManager } from './systems/AudioManager';
import { MusicPlayer } from './systems/MusicPlayer';
import { GameState } from './state/GameState';
import { Player } from './entities/Player';
import { EnemyGrid } from './entities/EnemyGrid';
import { BulletPool } from './entities/Bullet';
import { TargetRing } from './entities/TargetRing';
import { ExplosionSystem } from './entities/ExplosionSystem';
import { HUD } from './ui/HUD';
import { LevelBanner } from './ui/LevelBanner';
import { UpgradeMenu } from './ui/UpgradeMenu';
import { TouchControls } from './ui/TouchControls';
import { LeaderboardService } from './services/LeaderboardService';
import { InitialsEntryUI } from './ui/InitialsEntryUI';
import { getLevelConfig } from './levels/levelConfig';

const FIXED_DT = 1 / 60;
const MAX_FRAME = 0.1;

export class Game {
  private readonly renderer: THREE.WebGLRenderer;
  private readonly scene: THREE.Scene;
  private readonly camera: THREE.PerspectiveCamera;
  private readonly resizeScene: (aspect: number) => void;

  private readonly input = new InputManager();
  private readonly audio = new AudioManager();
  private readonly music = new MusicPlayer();
  private readonly state = new GameState();
  private readonly player: Player;
  private readonly enemies: EnemyGrid;
  private readonly bullets: BulletPool;
  private readonly targetRing = new TargetRing();
  private readonly explosions = new ExplosionSystem();
  private readonly hud: HUD;
  private readonly levelBanner: LevelBanner;
  private readonly upgradeMenu: UpgradeMenu;
  private readonly leaderboard = new LeaderboardService();
  private readonly initialsUI: InitialsEntryUI;
  private readonly touchControls: TouchControls;

  private accumulator = 0;
  private lastTime = 0;
  /** When true, player hits play their effect but never deduct a life (debug). */
  private godMode = false;
  /** Manual touch-control override: true=force on, false=force off, null=auto. */
  private touchOverride: boolean | null = null;
  /** Repeat timer (seconds) for joystick-driven letter cycling in initials. */
  private initialsRepeat = 0;
  /** Last joystick vertical sign consumed for initials letter cycling. */
  private initialsLastDir = 0;
  /** Last joystick horizontal sign consumed for initials cursor movement. */
  private initialsCursorDir = 0;

  constructor(private readonly container: HTMLElement) {
    this.renderer = createRenderer(container);
    const aspect = container.clientWidth / container.clientHeight;
    const built = createScene(aspect);
    this.scene = built.scene;
    this.camera = built.camera;
    this.resizeScene = built.resize;

    //lalala
    //
    this.player = new Player();
    this.scene.add(this.player.mesh);
    this.scene.add(this.player.guides);
    this.enemies = new EnemyGrid(this.scene);
    this.bullets = new BulletPool(this.scene);
    this.scene.add(this.targetRing.mesh);
    this.scene.add(this.explosions.group);

    this.hud = new HUD(
      container,
      () => this.start(),
      this.leaderboard,
      () => this.retry(),
    );
    this.levelBanner = new LevelBanner(container);
    this.upgradeMenu = new UpgradeMenu(container);
    this.initialsUI = new InitialsEntryUI(container);

    this.touchControls = new TouchControls(container, this.input);
    this.syncTouchControls();

    window.addEventListener('resize', this.onResize);
    window.addEventListener('orientationchange', this.onResize);
    this.player.mesh.visible = false;
    this.player.guides.visible = false;
    this.enemies.group.visible = false;

    this.installDebugConsole();
  }

  /**
   * Exposes a small debug API on `window.isoInvaders` so the level can be set
   * from the browser console, e.g.:
   *   isoInvaders.startLevel(5)  // restart immediately at level 5
   *   isoInvaders.setStartLevel(3); // applies on the next new game
   */
  private installDebugConsole(): void {
    const state = this.state;
    const restart = () => this.start();
    const api = {
      /** Set the level a *new* game will start at (takes effect on next start). */
      setStartLevel: (level: number): number => {
        state.startLevel = Math.max(1, Math.floor(level));
        return state.startLevel;
      },
      /** Immediately (re)start a fresh game at the given level. */
      startLevel: (level: number): number => {
        state.startLevel = Math.max(1, Math.floor(level));
        restart();
        return state.level;
      },
      /** Current level of the running game. */
      get level(): number {
        return state.level;
      },
      /** Force an immediate game over (debug/testing aid). */
      gameOver: (): void => {
        this.handleGameOver();
      },
      /** Set the current score (debug/testing aid). */
      setScore: (score: number): number => {
        state.score = Math.max(0, Math.floor(score));
        return state.score;
      },
      /**
       * Toggle invincibility: projectiles still hit the ship (impact effects
       * play), but lives are never deducted. Pass a boolean to set explicitly,
       * or omit to flip the current value. Returns the new state.
       *   isoInvaders.immortal()      // toggle
       *   isoInvaders.immortal(true)  // enable
       */
      immortal: (on?: boolean): boolean => {
        this.godMode = on ?? !this.godMode;
        return this.godMode;
      },
      /**
       * Force the on-screen touch controls on/off (overrides auto-detection).
       * Useful for testing in Chrome's device toolbar, which doesn't always
       * report a coarse pointer. Pass null to return to auto-detection.
       *   isoInvaders.touchControls(true)   // force show
       *   isoInvaders.touchControls(false)  // force hide
       *   isoInvaders.touchControls(null)   // auto
       */
      touchControls: (on?: boolean | null): boolean => {
        this.touchOverride = on === undefined ? true : on;
        this.syncTouchControls();
        return this.touchControls.isEnabled;
      },
    };
    (window as unknown as { isoInvaders: typeof api }).isoInvaders = api;
  }

  start(): void {
    this.state.reset();
    this.beginWave();
  }

  /**
   * Retry the level the player died on: keep the current level but reset score
   * to 0 and refill lives. Dismisses the initials-entry prompt if it's still
   * open (the player can retry instead of, or after, entering their initials).
   */
  retry(): void {
    this.initialsUI.hide();
    this.state.retryLevel();
    this.beginWave();
  }

  /** Spawns the fleet for the current level and starts/clears the run UI. */
  private beginWave(): void {
    this.upgradeMenu.hide();
    this.player.reset();
    this.player.speed = this.state.shipSpeed;
    this.player.mesh.visible = true;
    this.player.guides.visible = true;
    const config = getLevelConfig(this.state.level);
    this.enemies.spawnForLevel(config);
    this.enemies.group.visible = true;
    this.bullets.reset();
    this.bullets.enemyHoming = config.enemyHoming;
    this.targetRing.hide();
    this.explosions.reset();
    this.levelBanner.hide();
    this.hud.hideOverlay();
    this.hud.update(this.state);
    void this.music.playForLevel(this.state.level);
  }

  run(): void {
    this.armTitleMusic();
    this.lastTime = performance.now();
    requestAnimationFrame(this.loop);
  }

  /**
   * Plays the first song on the title screen, as soon as the game loads. Browser
   * autoplay policies block audio until a user gesture, so we attempt immediate
   * playback and also arm one-time listeners that kick it off on the very first
   * interaction (pointer/key/touch). Since the title music is level 1's song,
   * pressing Start later seamlessly continues the same track.
   */
  private armTitleMusic(): void {
    const begin = (): void => {
      void this.music.playForLevel(1);
    };
    // Best effort: some environments allow autoplay (e.g. after prior gesture).
    begin();
    const events: Array<keyof DocumentEventMap> = [
      'pointerdown',
      'keydown',
      'touchstart',
    ];
    const onGesture = (): void => {
      // Resume the AudioContext SYNCHRONOUSLY within the gesture first — mobile
      // browsers require this and won't honor a resume deferred behind awaits.
      this.music.resumeContext();
      begin();
      // Keep listening until audio is actually unlocked; the first tap on iOS
      // may go toward entering fullscreen/orientation, suspending the context.
      if (this.music.isUnlocked) {
        for (const ev of events) document.removeEventListener(ev, onGesture, true);
      }
    };
    // Capture phase on document so on-screen controls that stop propagation
    // (joystick/fire button, Start button) still trigger the unlock.
    for (const ev of events) {
      document.addEventListener(ev, onGesture, true);
    }
  }

  private loop = (now: number): void => {
    const frame = Math.min((now - this.lastTime) / 1000, MAX_FRAME);
    this.lastTime = now;

    if (this.state.status === 'playing') {
      this.accumulator += frame;
      while (this.accumulator >= FIXED_DT) {
        this.update(FIXED_DT);
        this.accumulator -= FIXED_DT;
      }
      this.updateAimLock(frame);
    } else if (this.state.status === 'entering_initials') {
      this.updateInitialsInput(frame);
    }

    // Advance explosions every frame so a death burst still plays out while
    // the game transitions to the over / initials-entry state.
    this.explosions.update(frame);

    this.renderer.render(this.scene, this.camera);
    requestAnimationFrame(this.loop);
  };

  /**
   * Routes joystick + fire input into the initials prompt so high scores can be
   * entered on touch devices without a keyboard. Joystick up/down cycles the
   * current letter (with an initial delay then auto-repeat while held); FIRE
   * (tap) advances to the next letter / confirms. Horizontal joystick nudges
   * move the cursor between slots.
   */
  private updateInitialsInput(frame: number): void {
    if (!this.initialsUI.isActive) return;

    // FIRE tap → advance / confirm.
    if (this.input.consumeFire()) {
      this.initialsUI.confirm();
    }

    const DEADZONE = 0.5;
    const FIRST_DELAY = 0.35; // seconds before auto-repeat kicks in
    const REPEAT = 0.16; // seconds between repeated steps while held

    const y = this.input.moveY; // +1 up, -1 down
    const x = this.input.moveX; // for cursor slot movement

    // Vertical: change the current letter.
    const dir = y > DEADZONE ? 1 : y < -DEADZONE ? -1 : 0;
    if (dir === 0) {
      this.initialsLastDir = 0;
      this.initialsRepeat = 0;
    } else if (dir !== this.initialsLastDir) {
      // New push in a direction: step immediately, then arm the repeat delay.
      this.initialsUI.cycleLetter(dir);
      this.initialsLastDir = dir;
      this.initialsRepeat = FIRST_DELAY;
    } else {
      this.initialsRepeat -= frame;
      if (this.initialsRepeat <= 0) {
        this.initialsUI.cycleLetter(dir);
        this.initialsRepeat = REPEAT;
      }
    }

    // Horizontal: move between letter slots (edge-triggered on the same timer
    // as vertical to avoid runaway). Only act on a fresh strong push.
    if (x > DEADZONE && this.initialsCursorDir !== 1) {
      this.initialsUI.moveCursor(1);
      this.initialsCursorDir = 1;
    } else if (x < -DEADZONE && this.initialsCursorDir !== -1) {
      this.initialsUI.moveCursor(-1);
      this.initialsCursorDir = -1;
    } else if (Math.abs(x) <= DEADZONE) {
      this.initialsCursorDir = 0;
    }
  }

  private updateAimLock(frame: number): void {
    const target = this.enemies.findAimTarget(
      this.player.mesh.position.x,
      this.player.mesh.position.y,
    );
    if (target) {
      this.targetRing.showAt(target.mesh.position);
    } else {
      this.targetRing.hide();
    }
    this.targetRing.update(frame);
  }

  private handleGameOver(): void {
    if (this.state.status === 'entering_initials') return;

    this.audio.gameOver();
    this.state.end();
    this.targetRing.hide();
    this.music.stop();

    // Always show the game-over overlay (with PLAY AGAIN + RETRY LEVEL). When
    // the score qualifies, also show the initials-entry prompt on top, so the
    // player can record their initials and still retry/replay from the buttons.
    this.hud.showGameOver(this.state);

    if (this.leaderboard.qualifies(this.state.score)) {
      this.state.status = 'entering_initials';
      this.initialsUI.show(this.state.score, (initials) => {
        this.leaderboard.save(initials, this.state.score);
        this.initialsUI.hide();
        if (this.state.status === 'entering_initials') {
          this.state.status = 'over';
        }
        this.hud.showGameOver(this.state);
      });
    }
  }

  private update(dt: number): void {
    if (this.player.update(dt, this.input)) {
      const muzzles = this.player.muzzlePositions(
        this.state.shotCount,
        CONFIG.player.upgrades.shotSpacing,
      );
      for (const m of muzzles) this.bullets.fire('player', m);
      this.audio.shoot();
    }

    const step = this.enemies.update(dt, this.bullets.activeCount('enemy'));
    for (const from of step.fireFrom) {
      this.bullets.fire('enemy', from);
    }
    if (step.reachedPlayer) {
      this.handleGameOver();
      return;
    }

    this.bullets.update(dt, this.player.mesh.position);
    this.resolveCollisions();

    if (this.state.status !== 'playing') return;

    this.hud.update(this.state);

    if (this.enemies.aliveCount === 0) {
      this.handleLevelCleared();
    }
  }

  /**
   * Fleet wiped out with lives remaining: award the scaling bonus, advance to
   * the next level, then pause and present the upgrade menu. The player picks
   * one stacking advantage; selecting it spawns the next (harder) wave.
   */
  private handleLevelCleared(): void {
    this.state.awardLevelClearBonus();
    this.state.advanceLevel();
    this.state.status = 'choosing_upgrade';
    this.targetRing.hide();
    this.hud.update(this.state);
    this.upgradeMenu.show(
      this.state.level,
      { extraShots: this.state.extraShots, speedPicks: this.state.speedPicks },
      (type) => {
        this.state.applyUpgrade(type);
        this.startNextWave();
      },
    );
  }

  /**
   * After an upgrade is chosen, spawn the next level's fleet, apply any speed
   * upgrade to the ship, flash the "LEVEL N" banner, and resume play.
   */
  private startNextWave(): void {
    const config = getLevelConfig(this.state.level);
    this.player.speed = this.state.shipSpeed;
    this.enemies.spawnForLevel(config);
    this.bullets.reset();
    this.bullets.enemyHoming = config.enemyHoming;
    this.targetRing.hide();
    this.levelBanner.show(this.state.level);
    this.audio.gameOver();
    this.state.status = 'playing';
    this.hud.update(this.state);
    void this.music.playForLevel(this.state.level);
  }

  private resolveCollisions(): void {
    for (const bullet of this.bullets.bullets) {
      if (!bullet.active) continue;

      if (bullet.owner === 'player') {
        for (const enemy of this.enemies.enemies) {
          if (!enemy.alive) continue;
          if (intersects(bullet.aabb, enemy.aabb)) {
            enemy.kill();
            bullet.deactivate();
            this.state.addScore(CONFIG.enemies.pointsPerKill);
            this.audio.explosion();
            break;
          }
        }
      } else if (intersects(bullet.aabb, this.player.aabb)) {
        bullet.deactivate();
        this.explosions.spawn(this.player.mesh.position);
        this.audio.playerHit();
        if (this.godMode) continue; // immortal: impact shows, life untouched
        this.state.loseLife();
        if (this.state.status === 'over') {
          this.handleGameOver();
        }
      }
    }
  }

  private onResize = (): void => {
    const w = this.container.clientWidth;
    const h = this.container.clientHeight;
    this.renderer.setSize(w, h);
    this.resizeScene(w / h);
    // Re-evaluate touch support so toggling Chrome's device mode (or attaching
    // a touchscreen) shows/hides the on-screen controls without a fresh load.
    this.syncTouchControls();
    // Entering fullscreen / rotating on mobile can suspend the AudioContext;
    // resume it if we'd previously unlocked audio so the music keeps playing.
    if (this.music.isUnlocked) this.music.resumeContext();
  };

  /**
   * Enable/disable the on-screen touch controls based on the manual override
   * (if set) or auto-detection of a touch-capable device.
   */
  private syncTouchControls(): void {
    const want = this.touchOverride ?? TouchControls.isTouchDevice();
    if (want && !this.touchControls.isEnabled) this.touchControls.enable();
    else if (!want && this.touchControls.isEnabled)
      this.touchControls.disable();
  }
}
