/**
 * Arcade-style initials entry (three letters). Driven by either the keyboard
 * (Arrow Up/Down to change a letter, Arrow Right to advance/confirm) or by
 * touch — both the on-screen buttons rendered here and the game's joystick/fire
 * controls (routed in via the public {@link cycleLetter}/{@link moveCursor}/
 * {@link confirm} methods).
 */
export class InitialsEntryUI {
  private readonly container: HTMLElement;
  private overlay: HTMLDivElement | null = null;
  private letterEls: HTMLElement[] = [];
  private letters: number[] = [0, 0, 0];
  private currentPosition = 0;
  private active = false;
  private onComplete: ((initials: string) => void) | null = null;

  constructor(container: HTMLElement) {
    this.container = container;
    this.handleKeyDown = this.handleKeyDown.bind(this);
  }

  /** True while the prompt is showing and accepting input. */
  get isActive(): boolean {
    return this.active;
  }

  show(score: number, onComplete: (initials: string) => void): void {
    this.onComplete = onComplete;
    this.letters = [0, 0, 0];
    this.currentPosition = 0;
    this.active = true;

    this.overlay = document.createElement('div');
    this.overlay.id = 'initials-overlay';

    const scoreEl = document.createElement('p');
    scoreEl.textContent = `SCORE: ${score}`;
    this.overlay.appendChild(scoreEl);

    const lettersContainer = document.createElement('div');
    lettersContainer.className = 'initials-letters';
    this.letterEls = [];
    for (let i = 0; i < 3; i++) {
      const el = document.createElement('span');
      el.setAttribute('data-letter', String(i));
      el.textContent = 'A';
      this.letterEls.push(el);
      lettersContainer.appendChild(el);
    }
    this.overlay.appendChild(lettersContainer);

    // On-screen touch buttons (▲ / ▼ change the letter, ▶ advances/confirms).
    // These give a tap-only path on devices without a keyboard, in addition to
    // the joystick/fire routing the game does while this prompt is active.
    const pad = document.createElement('div');
    pad.className = 'initials-pad';
    const mkBtn = (label: string, onTap: () => void, cls = ''): HTMLButtonElement => {
      const b = document.createElement('button');
      b.type = 'button';
      b.className = `initials-btn ${cls}`.trim();
      b.textContent = label;
      // pointerdown for snappy response; prevent the page-level gesture handlers
      // from treating it as a game tap.
      b.addEventListener('pointerdown', (e) => {
        e.preventDefault();
        e.stopPropagation();
        onTap();
      });
      return b;
    };
    pad.append(
      mkBtn('▲', () => this.cycleLetter(1), 'up'),
      mkBtn('▼', () => this.cycleLetter(-1), 'down'),
      mkBtn('OK ▶', () => this.confirm(), 'ok'),
    );
    this.overlay.appendChild(pad);

    const hint = document.createElement('p');
    hint.className = 'initials-hint';
    hint.textContent = 'Joystick: up/down change · right or FIRE: select';
    this.overlay.appendChild(hint);

    this.container.appendChild(this.overlay);
    this.highlightActive();
    document.addEventListener('keydown', this.handleKeyDown);
  }

  hide(): void {
    this.active = false;
    this.onComplete = null;
    document.removeEventListener('keydown', this.handleKeyDown);
    if (this.overlay) {
      this.overlay.remove();
      this.overlay = null;
    }
  }

  /** Changes the current letter by `delta` (wraps A..Z). */
  cycleLetter(delta: number): void {
    if (!this.active) return;
    const next = (this.letters[this.currentPosition] + (delta % 26) + 26) % 26;
    this.letters[this.currentPosition] = next;
    this.updateDisplay();
  }

  /** Moves the cursor between letter slots by `delta` (clamped to 0..2). */
  moveCursor(delta: number): void {
    if (!this.active) return;
    const next = Math.max(0, Math.min(2, this.currentPosition + delta));
    if (next !== this.currentPosition) {
      this.currentPosition = next;
      this.highlightActive();
    }
  }

  /**
   * Advances to the next letter slot, or commits the initials if already on the
   * last slot. This is what FIRE / the OK button / Arrow Right trigger.
   */
  confirm(): void {
    if (!this.active) return;
    if (this.currentPosition < 2) {
      this.currentPosition++;
      this.highlightActive();
    } else {
      const initials = this.letters.map((i) => String.fromCharCode(65 + i)).join('');
      this.onComplete?.(initials);
    }
  }

  private handleKeyDown(e: KeyboardEvent): void {
    if (!this.active) return;

    switch (e.key) {
      case 'ArrowUp':
        this.cycleLetter(1);
        break;
      case 'ArrowDown':
        this.cycleLetter(-1);
        break;
      case 'ArrowRight':
        this.confirm();
        break;
    }
  }

  private highlightActive(): void {
    this.letterEls.forEach((el, i) => {
      el.classList.toggle('active', i === this.currentPosition);
    });
  }

  private updateDisplay(): void {
    for (let i = 0; i < 3; i++) {
      this.letterEls[i].textContent = String.fromCharCode(65 + this.letters[i]);
    }
  }
}
