import * as THREE from 'three';
import { CONFIG } from '../config';

/**
 * A small pulsing ring shown on the enemy that the aim line is locked onto.
 * It expands and fades on a loop while visible, drawing the player's eye to
 * the target they're currently aligned with.
 */
export class TargetRing {
  readonly mesh: THREE.Mesh;
  private phase = 0;

  constructor() {
    const geometry = new THREE.RingGeometry(0.7, 0.85, 32);
    const material = new THREE.MeshBasicMaterial({
      color: CONFIG.player.lockRingColor,
      transparent: true,
      opacity: 0,
      side: THREE.DoubleSide,
      depthWrite: false,
    });
    this.mesh = new THREE.Mesh(geometry, material);
    this.mesh.visible = false;
  }

  /** Place the ring on the target and (re)enable the pulse. */
  showAt(position: THREE.Vector3): void {
    if (!this.mesh.visible) {
      this.mesh.visible = true;
      this.phase = 0;
    }
    // Sit slightly in front of the enemy (toward the player) so it reads clearly.
    this.mesh.position.set(position.x, position.y, position.z - 0.6);
  }

  hide(): void {
    this.mesh.visible = false;
    (this.mesh.material as THREE.MeshBasicMaterial).opacity = 0;
  }

  update(dt: number): void {
    if (!this.mesh.visible) return;
    this.phase += dt * CONFIG.player.lockRingPulse;
    const t = this.phase % 1; // 0..1 loop
    const min = CONFIG.player.lockRingMinRadius;
    const max = CONFIG.player.lockRingMaxRadius;
    const scale = min + (max - min) * t;
    this.mesh.scale.setScalar(scale);
    // Fade out as the ring expands.
    (this.mesh.material as THREE.MeshBasicMaterial).opacity = 0.8 * (1 - t);
  }
}
