import { CONFIG } from '../config';
import { LEVELS } from './levels';

/**
 * Per-level difficulty configuration. Each level number resolves to one of
 * these; later levels make the fleet faster, fire more, and stack more
 * depth-layers of enemies. Levels beyond the explicitly defined set are
 * produced by monotonic scaling so difficulty never decreases.
 */
export interface LevelConfig {
  /** The level this config describes (>= 1). */
  level: number;
  /** Number of depth-layers (rows stacked along Z) of enemies. */
  layers: number;
  /** Seconds between fleet marches (smaller = faster). */
  stepInterval: number;
  /** Forward lunge distance per edge bounce (larger = advances faster). */
  stepZ: number;
  /** Per-eligible-enemy probability of firing per step. */
  fireChance: number;
  /** Cap on enemies firing in a single step. */
  maxShotsPerStep: number;
  /**
   * How strongly enemy projectiles steer toward the ship each second (the
   * homing/tracking strength). 0 = straight shots; higher = tighter tracking.
   */
  enemyHoming: number;
}

/**
 * Resolves the configuration for a given level. Defined levels come from the
 * explicit table; beyond it, difficulty is scaled. Levels < 1 are treated as 1.
 */
export function getLevelConfig(level: number): LevelConfig {
  const l = Math.max(1, Math.floor(level));
  const last = LEVELS[LEVELS.length - 1];

  if (l <= LEVELS.length) {
    return LEVELS[l - 1];
  }

  // Beyond the defined set: scale the last config monotonically so difficulty
  // keeps increasing (and never decreases) the deeper the player goes.
  const k = CONFIG.levels;
  const extra = l - LEVELS.length;
  return {
    level: l,
    layers: Math.min(k.maxLayers, l),
    stepInterval: last.stepInterval * Math.pow(k.stepIntervalFactor, extra),
    stepZ: last.stepZ * Math.pow(k.stepZFactor, extra),
    fireChance: Math.min(
      k.fireChanceMax,
      last.fireChance * Math.pow(k.fireChanceFactor, extra),
    ),
    maxShotsPerStep: last.maxShotsPerStep,
    enemyHoming: Math.min(
      k.enemyHomingMax,
      last.enemyHoming * Math.pow(k.enemyHomingFactor, extra),
    ),
  };
}
