import { Game } from './Game';
import { enterImmersive } from './systems/fullscreen';

const container = document.getElementById('app');
if (!container) {
  throw new Error('Missing #app container element');
}

// Single button on the portrait "rotate" gate: enter fullscreen AND lock to
// landscape in one user gesture (orientation lock requires fullscreen first).
const immersiveBtn = document.getElementById('immersive-btn');
immersiveBtn?.addEventListener('click', () => {
  void enterImmersive(container);
});

const game = new Game(container);
game.run();
