import * as THREE from 'three';
import { CONFIG } from '../config';
import { Enemy } from './Enemy';
import type { LevelConfig } from '../levels/levelConfig';

export interface StepResult {
  /** Positions from which enemies decided to fire this step. */
  fireFrom: { x: number; y: number; z: number }[];
  /** True if the formation reached the player's line (loss condition). */
  reachedPlayer: boolean;
}

/**
 * The invader matrix. Marches sideways and lunges forward (toward the player,
 * i.e. decreasing Z) when it hits a horizontal edge — the classic Space
 * Invaders cadence, adapted to 3D depth.
 */
export class EnemyGrid {
  readonly enemies: Enemy[] = [];
  readonly group = new THREE.Group();

  private dir = 1; // +1 right, -1 left
  private offsetX = 0;
  private offsetZ = 0;
  private offsetY = 0; // continuous vertical bob
  private bobTime = 0;
  private stepTimer = 0;
  /** Active level config; when set, the fleet is laid out as depth-layers. */
  private activeConfig: LevelConfig | null = null;

  constructor(scene: THREE.Scene) {
    const { cols, rows } = CONFIG.enemies;
    const maxLayers = CONFIG.levels.maxLayers;
    // Full 3D fleet pool: cols (X) × rows (Y) × maxLayers (Z depth). A level
    // reveals the first `layers` depth-slices; the 5 vertical rows are always
    // present in every revealed slice.
    for (let layer = 0; layer < maxLayers; layer++) {
      for (let row = 0; row < rows; row++) {
        for (let col = 0; col < cols; col++) {
          const enemy = new Enemy(col, row, layer);
          this.enemies.push(enemy);
          this.group.add(enemy.mesh);
          this.group.add(enemy.shadow);
        }
      }
    }
    scene.add(this.group);
    this.reset();
  }

  reset(): void {
    this.dir = 1;
    this.offsetX = 0;
    this.offsetZ = 0;
    this.offsetY = 0;
    this.bobTime = 0;
    this.stepTimer = 0;
    // Default (non-level) reset shows only the front depth-slice so the legacy
    // single-plane fleet (cols × rows) is preserved.
    for (const enemy of this.enemies) {
      if (enemy.layer === 0) enemy.revive();
      else enemy.kill();
    }
    this.layout();
  }

  /**
   * Rebuild/reposition the fleet for the given level: reveals `config.layers`
   * depth-slices (stacked along Z), each containing the full grid of vertical
   * rows × columns. Deeper levels add more depth-slices, not more rows.
   */
  spawnForLevel(config: LevelConfig): void {
    this.activeConfig = config;
    this.dir = 1;
    this.offsetX = 0;
    this.offsetZ = 0;
    this.offsetY = 0;
    this.bobTime = 0;
    this.stepTimer = 0;
    for (const enemy of this.enemies) {
      if (enemy.layer < config.layers) {
        enemy.revive();
      } else {
        enemy.kill();
      }
    }
    this.layout();
  }

  /**
   * The front-most living enemy of each firing lane. A "lane" is a fixed
   * column+row position projected along the depth (Z) axis; only the closest
   * living enemy in a lane (smallest layer) may fire, since the ones behind it
   * are blocked by a friendly in front.
   */
  frontLineEnemies(): Enemy[] {
    const front = new Map<string, Enemy>();
    for (const enemy of this.enemies) {
      if (!enemy.alive) continue;
      const lane = `${enemy.col},${enemy.row}`;
      const current = front.get(lane);
      if (!current || enemy.layer < current.layer) {
        front.set(lane, enemy);
      }
    }
    return [...front.values()];
  }

  /**
   * Maximum horizontal offset that keeps the outermost columns within the
   * ship's reachable X range (so every invader is always hittable, and their
   * shots originate from reachable space).
   */
  private get maxOffsetX(): number {
    const e = CONFIG.enemies;
    const colHalfSpan = ((e.cols - 1) / 2) * e.spacingX; // center to edge column
    return Math.max(0, CONFIG.bounds.x - colHalfSpan);
  }

  /** Vertical offset range [min, max] that keeps all rows within ship reach. */
  private get offsetYRange(): { min: number; max: number } {
    const e = CONFIG.enemies;
    const topRowY = e.originY; // row 0
    const bottomRowY = e.originY - (e.rows - 1) * e.spacingY;
    return {
      min: CONFIG.bounds.yMin - bottomRowY,
      max: CONFIG.bounds.yMax - topRowY,
    };
  }

  /** Positions every enemy according to its grid coords + current offsets. */
  private layout(): void {
    const e = CONFIG.enemies;
    const halfCols = (e.cols - 1) / 2;
    const floorY = CONFIG.playfield.floorY;
    const zRange = Math.max(1e-3, e.startZ - e.loseZ);
    for (const enemy of this.enemies) {
      const x = (enemy.col - halfCols) * e.spacingX + this.offsetX;
      // Rows always stack vertically (Y); depth-layers always stack along Z.
      const y = e.originY - enemy.row * e.spacingY + this.offsetY;
      const z = e.startZ - this.offsetZ + enemy.layer * e.layerSpacingZ;
      enemy.mesh.position.set(x, y, z);
      // Proximity 0 (at start depth) .. 1 (reaching the player line).
      const t = clamp((e.startZ - z) / zRange, 0, 1);
      enemy.positionShadow(x, z, floorY, t);
    }
  }

  get aliveCount(): number {
    return this.enemies.reduce((n, e) => n + (e.alive ? 1 : 0), 0);
  }

  /** Frontmost (closest to player) Z among living enemies. */
  get frontZ(): number {
    let min = Infinity;
    for (const enemy of this.enemies) {
      if (enemy.alive) min = Math.min(min, enemy.mesh.position.z);
    }
    return min;
  }

  /**
   * Returns the living enemy the aim line (a +Z ray at the given X/Y) is
   * currently lined up with, or null. Picks the closest one to the player so
   * the lock indicator sits on the enemy you'd actually hit first.
   */
  findAimTarget(aimX: number, aimY: number): Enemy | null {
    const hx = CONFIG.enemies.size.x / 2;
    const hy = CONFIG.enemies.size.y / 2;
    let best: Enemy | null = null;
    let bestZ = Infinity;
    for (const enemy of this.enemies) {
      if (!enemy.alive) continue;
      const p = enemy.mesh.position;
      if (Math.abs(p.x - aimX) <= hx && Math.abs(p.y - aimY) <= hy) {
        if (p.z < bestZ) {
          bestZ = p.z;
          best = enemy;
        }
      }
    }
    return best;
  }

  /**
   * Advances the formation one tick. `activeEnemyShots` is the number of enemy
   * bullets currently in flight, used to honor the on-screen shot cap.
   */
  update(dt: number, activeEnemyShots = 0): StepResult {
    const result: StepResult = { fireFrom: [], reachedPlayer: false };
    const e = CONFIG.enemies;
    const cfg = this.activeConfig;
    // Per-level difficulty values, falling back to the static config when the
    // fleet was created without a level (legacy/constructor path).
    const stepInterval = cfg ? cfg.stepInterval : e.stepInterval;
    const stepZ = cfg ? cfg.stepZ : e.stepZ;
    const fireChance = cfg ? cfg.fireChance : e.fireChance;
    const maxShotsPerStep = cfg ? cfg.maxShotsPerStep : e.maxShotsPerStep;

    // Continuous vertical bob — runs every frame, in parallel with the stepped
    // sideways march and forward advance below. Clamped so no row ever leaves
    // the ship's reachable vertical range.
    if (e.bobAmplitude > 0) {
      this.bobTime += dt;
      const range = this.offsetYRange;
      const raw =
        Math.sin(this.bobTime * e.bobSpeed * Math.PI * 2) * e.bobAmplitude;
      this.offsetY = clamp(raw, range.min, range.max);
      this.layout();
    }

    this.stepTimer += dt;
    if (this.stepTimer < stepInterval) return result;
    this.stepTimer = 0;

    // Advance the two-frame "walk" animation on every march step.
    for (const enemy of this.enemies) {
      if (enemy.alive) enemy.toggleFrame();
    }

    // March sideways, bouncing at whichever limit is reached first: the
    // configured travel limit or the edge of the ship's reachable X range
    // (so the outermost columns always stay hittable).
    const limitX = Math.min(e.edgeX, this.maxOffsetX);
    const nextOffset = this.offsetX + this.dir * e.stepX;

    if (Math.abs(nextOffset) > limitX) {
      // Hit an edge: reverse direction and lunge forward toward the player.
      this.dir *= -1;
      this.offsetZ += stepZ;
      this.offsetX = clamp(this.offsetX, -limitX, limitX);
    } else {
      this.offsetX = nextOffset;
    }
    this.layout();

    // How many more shots are allowed this step, respecting both the
    // per-step cap and the on-screen active-shot cap.
    let budget: number = maxShotsPerStep;
    if (e.maxActiveShots > 0) {
      budget = Math.min(budget, e.maxActiveShots - activeEnemyShots);
    }

    // Only the front-most living enemy of each column may fire (no enemy can
    // shoot through one of its own column-mates closer to the player). When a
    // level is active this uses the depth-layer ordering; otherwise every
    // living enemy is its own column's front line (single layer).
    const shooters = this.activeConfig ? this.frontLineEnemies() : this.enemies;
    for (const enemy of shooters) {
      if (budget <= 0) break;
      if (!enemy.alive) continue;
      if (Math.random() < fireChance) {
        result.fireFrom.push({
          x: enemy.mesh.position.x,
          y: enemy.mesh.position.y,
          z: enemy.mesh.position.z - e.size.z,
        });
        budget--;
      }
    }

    if (this.frontZ <= e.loseZ) result.reachedPlayer = true;
    return result;
  }
}

function clamp(v: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, v));
}
