import * as THREE from 'three';

/**
 * Builds an 8-bit / voxel-style 3D space fighter jet as a small assembly of
 * box "blocks": a chunky fuselage with a pointed nose, swept delta wings with
 * tip pods, a raised cockpit canopy, twin tail fins, and glowing engine
 * exhausts at the rear. Designed to face +Z (toward the invaders).
 *
 * The whole jet is centered on the origin and scaled to roughly fit a 1x1x1
 * box; the caller scales the returned group to the desired world size so the
 * existing AABB collision box stays valid.
 */
export function buildPlayerShip(): {
  group: THREE.Group;
  engineGlow: THREE.Mesh[];
} {
  const group = new THREE.Group();

  const hull = new THREE.MeshStandardMaterial({
    color: 0x6fd3ff,
    emissive: 0x0b2740,
    metalness: 0.45,
    roughness: 0.35,
  });
  const hullDark = new THREE.MeshStandardMaterial({
    color: 0x2f7fb5,
    emissive: 0x08283f,
    metalness: 0.5,
    roughness: 0.4,
  });
  const accent = new THREE.MeshStandardMaterial({
    color: 0xff5a4d,
    emissive: 0x611008,
    metalness: 0.3,
    roughness: 0.5,
  });
  const canopy = new THREE.MeshStandardMaterial({
    color: 0x1c2a3a,
    emissive: 0x0a141f,
    metalness: 0.2,
    roughness: 0.15,
  });
  const engineMat = new THREE.MeshBasicMaterial({ color: 0xffd23a });

  const block = (
    w: number,
    h: number,
    d: number,
    x: number,
    y: number,
    z: number,
    mat: THREE.Material,
  ): THREE.Mesh => {
    const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), mat);
    m.position.set(x, y, z);
    group.add(m);
    return m;
  };

  // --- Fuselage: stacked blocks tapering toward the nose (+Z). ---
  block(0.34, 0.26, 0.7, 0, 0, -0.05, hull); // main body
  block(0.26, 0.2, 0.35, 0, 0.01, 0.34, hull); // forward section
  block(0.16, 0.14, 0.3, 0, 0.02, 0.62, hull); // nose taper
  block(0.08, 0.08, 0.18, 0, 0.03, 0.82, accent); // nose tip / cannon

  // --- Cockpit canopy on top, slightly forward. ---
  block(0.18, 0.12, 0.26, 0, 0.18, 0.18, canopy);

  // --- Swept delta wings (lower, mid-body), one block per side plus tip. ---
  for (const s of [-1, 1]) {
    block(0.34, 0.06, 0.4, s * 0.34, -0.04, -0.04, hullDark); // inner wing
    block(0.26, 0.06, 0.26, s * 0.62, -0.04, -0.16, hullDark); // outer wing (swept back)
    block(0.08, 0.1, 0.3, s * 0.78, 0, -0.12, accent); // wingtip pod / missile rail
  }

  // --- Twin tail fins at the rear, angled up. ---
  for (const s of [-1, 1]) {
    block(0.05, 0.22, 0.18, s * 0.12, 0.14, -0.36, hullDark);
  }
  // --- Center dorsal fin. ---
  block(0.05, 0.2, 0.2, 0, 0.16, -0.34, hull);

  // --- Engine exhausts at the back (-Z), glowing. ---
  const engineGlow: THREE.Mesh[] = [];
  for (const s of [-1, 1]) {
    const e = block(0.12, 0.12, 0.1, s * 0.1, -0.02, -0.42, engineMat);
    engineGlow.push(e);
  }

  return { group, engineGlow };
}
