/**
 * Cross-browser fullscreen helpers. The Fullscreen API must be invoked from a
 * user gesture (e.g. a click/tap handler), so callers should request fullscreen
 * directly inside such handlers.
 */

interface FullscreenElement extends HTMLElement {
  webkitRequestFullscreen?: () => Promise<void> | void;
}

interface FullscreenDocument extends Document {
  webkitFullscreenElement?: Element | null;
  webkitExitFullscreen?: () => Promise<void> | void;
}

/** True if the Fullscreen API is available in this browser. */
export function fullscreenSupported(): boolean {
  if (typeof document === 'undefined') return false;
  const el = document.documentElement as FullscreenElement;
  return Boolean(el.requestFullscreen || el.webkitRequestFullscreen);
}

/** True if the page is currently displayed fullscreen. */
export function isFullscreen(): boolean {
  if (typeof document === 'undefined') return false;
  const doc = document as FullscreenDocument;
  return Boolean(doc.fullscreenElement || doc.webkitFullscreenElement);
}

/** Requests fullscreen on the given element (defaults to the document root). */
export async function requestFullscreen(target?: HTMLElement): Promise<void> {
  const el = (target ?? document.documentElement) as FullscreenElement;
  try {
    if (el.requestFullscreen) await el.requestFullscreen();
    else if (el.webkitRequestFullscreen) await el.webkitRequestFullscreen();
  } catch {
    // Ignore: some browsers reject (e.g. not from a gesture); not fatal.
  }
}

/** Exits fullscreen if currently active. */
export async function exitFullscreen(): Promise<void> {
  const doc = document as FullscreenDocument;
  try {
    if (doc.exitFullscreen) await doc.exitFullscreen();
    else if (doc.webkitExitFullscreen) await doc.webkitExitFullscreen();
  } catch {
    // Ignore.
  }
}

/** Toggles fullscreen for the given element (defaults to the document root). */
export async function toggleFullscreen(target?: HTMLElement): Promise<void> {
  if (isFullscreen()) await exitFullscreen();
  else await requestFullscreen(target);
}

interface OrientationLock extends ScreenOrientation {
  lock?: (orientation: 'landscape' | 'portrait' | 'any' | 'natural') => Promise<void>;
}

/**
 * Attempts to lock the screen to landscape. This only works while the document
 * is fullscreen (browser requirement) and on devices that support the Screen
 * Orientation API (mainly Android). Silently no-ops elsewhere (e.g. iOS).
 */
export async function lockLandscape(): Promise<void> {
  if (typeof screen === 'undefined') return;
  const orientation = screen.orientation as OrientationLock | undefined;
  try {
    await orientation?.lock?.('landscape');
  } catch {
    // Not supported / not allowed (e.g. iOS, or not fullscreen): ignore.
  }
}

/**
 * Enters fullscreen on the target element and then tries to lock landscape.
 * Must be called from a user gesture. Returns once both have been attempted.
 */
export async function enterImmersive(target?: HTMLElement): Promise<void> {
  if (fullscreenSupported() && !isFullscreen()) await requestFullscreen(target);
  await lockLandscape();
}

/**
 * Subscribes to fullscreen change events (standard + webkit). Returns an
 * unsubscribe function.
 */
export function onFullscreenChange(handler: () => void): () => void {
  document.addEventListener('fullscreenchange', handler);
  document.addEventListener('webkitfullscreenchange', handler);
  return () => {
    document.removeEventListener('fullscreenchange', handler);
    document.removeEventListener('webkitfullscreenchange', handler);
  };
}
