import * as THREE from 'three';
import { CONFIG } from '../config';

/**
 * A true 3D missile model for projectiles: a cylindrical body, a conical nose
 * cone, three swept tail fins, and a pulsing conical exhaust flame. The missile
 * is fitted within CONFIG.bullet.size so the existing AABB collision box stays
 * valid. Its local +Z is the nose direction; callers rotate the group 180°
 * about Y for enemy missiles that travel -Z.
 */

export interface RocketMesh {
  group: THREE.Group;
  /** Advance the exhaust-flame animation. */
  tick(dt: number): void;
  /** Recolor the missile body (player vs enemy). */
  setColor(color: number, emissive: number): void;
}

/** Soft radial-gradient texture, built once and shared by all halo sprites. */
let _haloTexture: THREE.Texture | null = null;
function haloTexture(): THREE.Texture {
  if (_haloTexture) return _haloTexture;
  const s = 128;
  const canvas = document.createElement('canvas');
  canvas.width = s;
  canvas.height = s;
  const ctx = canvas.getContext('2d')!;
  const g = ctx.createRadialGradient(s / 2, s / 2, 0, s / 2, s / 2, s / 2);
  g.addColorStop(0, 'rgba(255,255,255,1)');
  g.addColorStop(0.25, 'rgba(255,255,255,0.6)');
  g.addColorStop(0.6, 'rgba(255,255,255,0.15)');
  g.addColorStop(1, 'rgba(255,255,255,0)');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, s, s);
  _haloTexture = new THREE.CanvasTexture(canvas);
  return _haloTexture;
}

export function buildRocketMesh(): RocketMesh {
  const size = CONFIG.bullet.size;
  // Total missile length runs along Z; radius scales with the bullet width.
  // 0.85 applies a 15% size reduction over the previous proportions.
  const length = size.z * 0.78 * 0.85;
  const radius = Math.max(size.x, size.y) * 1.0 * 0.85;

  const noseLen = length * 0.3;
  const bodyLen = length * 0.5;
  const flameLen = length * 0.38;

  // Nose, body, and fins all share the owner's solid color (set via setColor).
  const bodyMaterial = new THREE.MeshStandardMaterial({
    color: 0xff5577,
    emissive: 0x661122,
    emissiveIntensity: 0.55,
    metalness: 0.35,
    roughness: 0.4,
  });
  const noseMaterial = new THREE.MeshStandardMaterial({
    color: 0xff5577,
    emissive: 0x661122,
    emissiveIntensity: 0.55,
    metalness: 0.4,
    roughness: 0.35,
  });
  const finMaterial = new THREE.MeshStandardMaterial({
    color: 0xff5577,
    emissive: 0x661122,
    emissiveIntensity: 0.55,
    metalness: 0.35,
    roughness: 0.4,
  });
  const flameMaterial = new THREE.MeshStandardMaterial({
    color: 0xffd14d,
    emissive: 0xff7a18,
    emissiveIntensity: 1.6,
    metalness: 0,
    roughness: 0.6,
    transparent: true,
    opacity: 0.95,
  });

  const group = new THREE.Group();

  // Body cylinder (Y-up by default → rotate to align with +Z).
  const body = new THREE.Mesh(
    new THREE.CylinderGeometry(radius, radius, bodyLen, 16),
    bodyMaterial,
  );
  body.rotation.x = Math.PI / 2;
  body.position.z = bodyLen / 2;
  group.add(body);

  // Nose cone at the front.
  const nose = new THREE.Mesh(
    new THREE.ConeGeometry(radius, noseLen, 16),
    noseMaterial,
  );
  nose.rotation.x = Math.PI / 2;
  nose.position.z = bodyLen + noseLen / 2;
  group.add(nose);

  // Three tail fins, evenly spaced around the rear of the body.
  const finGeom = new THREE.BoxGeometry(radius * 0.18, radius * 1.7, bodyLen * 0.5);
  for (let i = 0; i < 3; i++) {
    const fin = new THREE.Mesh(finGeom, finMaterial);
    fin.position.z = bodyLen * 0.22;
    fin.position.y = radius * 0.9;
    const pivot = new THREE.Group();
    pivot.add(fin);
    pivot.rotation.z = (i / 3) * Math.PI * 2;
    group.add(pivot);
  }

  // Exhaust flame: a cone pointing backward (-Z) from the nozzle.
  const flame = new THREE.Mesh(
    new THREE.ConeGeometry(radius * 0.85, flameLen, 12),
    flameMaterial,
  );
  flame.rotation.x = -Math.PI / 2; // tip points -Z
  flame.position.z = -flameLen / 2;
  group.add(flame);

  // Fuzzy halo: a camera-facing additive sprite tinted to the missile color.
  const haloMaterial = new THREE.SpriteMaterial({
    map: haloTexture(),
    color: 0xff5577,
    blending: THREE.AdditiveBlending,
    transparent: true,
    depthWrite: false,
    opacity: 0.85,
  });
  const halo = new THREE.Sprite(haloMaterial);
  const haloSize = length * 1.9;
  halo.scale.set(haloSize, haloSize, 1);
  // Sit the halo behind the missile, around the exhaust, so it reads as a
  // trailing rocket glow rather than wrapping the whole body.
  halo.position.z = -flameLen * 0.6;
  group.add(halo);

  let elapsed = 0;
  const baseFlame = flameLen;

  return {
    group,
    tick(dt: number): void {
      // Pulse the flame length/opacity for a lively exhaust.
      elapsed += dt;
      const pulse = 0.75 + 0.35 * Math.abs(Math.sin(elapsed * 30));
      flame.scale.set(1, pulse, 1);
      flame.position.z = -(baseFlame * pulse) / 2;
      flameMaterial.opacity = 0.7 + 0.25 * Math.abs(Math.sin(elapsed * 30));
    },
    setColor(color: number, emissive: number): void {
      for (const m of [bodyMaterial, noseMaterial, finMaterial]) {
        m.color.set(color);
        m.emissive.set(emissive);
      }
      haloMaterial.color.set(color);
    },
  };
}
