import type { InputManager } from '../systems/InputManager';

/**
 * On-screen touch controls for mobile/tablet (landscape): an analog joystick on
 * the LEFT (left thumb → movement) and a fire button on the RIGHT (right thumb →
 * shoot). Translates pointer gestures into InputManager calls. Hidden by default;
 * call {@link enable} on touch-capable devices.
 *
 * Pointer events are used so each finger is tracked independently by pointerId,
 * allowing simultaneous move + fire.
 */
export class TouchControls {
  private readonly root: HTMLDivElement;
  private readonly stickBase: HTMLDivElement;
  private readonly stickKnob: HTMLDivElement;
  private readonly fireButton: HTMLDivElement;

  /** pointerId currently driving the joystick, or null. */
  private stickPointer: number | null = null;
  private stickCx = 0;
  private stickCy = 0;
  private maxRadius = 56;

  private firePointer: number | null = null;
  private enabled = false;

  constructor(
    container: HTMLElement,
    private readonly input: InputManager,
  ) {
    this.root = document.createElement('div');
    this.root.id = 'touch-controls';
    this.root.classList.add('hidden');

    // Fire button (right side).
    this.fireButton = document.createElement('div');
    this.fireButton.className = 'touch-fire';
    this.fireButton.innerHTML = `
      <svg viewBox="0 0 64 64" aria-hidden="true">
        <path d="M32 6 L40 26 L40 44 L24 44 L24 26 Z" fill="currentColor"/>
        <path d="M24 44 L18 56 L46 56 L40 44 Z" fill="currentColor" opacity="0.7"/>
      </svg>`;

    // Joystick (left side): a base ring with a draggable knob.
    this.stickBase = document.createElement('div');
    this.stickBase.className = 'touch-stick';
    this.stickKnob = document.createElement('div');
    this.stickKnob.className = 'touch-stick-knob';
    this.stickBase.append(this.stickKnob);

    this.root.append(this.fireButton, this.stickBase);
    container.append(this.root);

    this.bind();
  }

  /** Detects a touch-capable device (coarse pointer / touch points). */
  static isTouchDevice(): boolean {
    if (typeof window === 'undefined') return false;
    return (
      'ontouchstart' in window ||
      (navigator.maxTouchPoints ?? 0) > 0 ||
      window.matchMedia?.('(pointer: coarse)').matches === true
    );
  }

  enable(): void {
    this.enabled = true;
    this.root.classList.remove('hidden');
  }

  disable(): void {
    this.enabled = false;
    this.root.classList.add('hidden');
    this.resetStick();
    this.input.setFireHeld(false);
    this.firePointer = null;
  }

  private bind(): void {
    // --- Fire button ---
    this.fireButton.addEventListener('pointerdown', (e) => {
      e.preventDefault();
      this.firePointer = e.pointerId;
      this.input.pressFire();
      this.input.setFireHeld(true);
      this.fireButton.classList.add('active');
    });
    const endFire = (e: PointerEvent): void => {
      if (e.pointerId !== this.firePointer) return;
      this.firePointer = null;
      this.input.setFireHeld(false);
      this.fireButton.classList.remove('active');
    };
    this.fireButton.addEventListener('pointerup', endFire);
    this.fireButton.addEventListener('pointercancel', endFire);
    this.fireButton.addEventListener('pointerleave', endFire);

    // --- Joystick ---
    this.stickBase.addEventListener('pointerdown', (e) => {
      e.preventDefault();
      this.stickPointer = e.pointerId;
      this.stickBase.setPointerCapture(e.pointerId);
      const rect = this.stickBase.getBoundingClientRect();
      this.stickCx = rect.left + rect.width / 2;
      this.stickCy = rect.top + rect.height / 2;
      this.maxRadius = rect.width / 2;
      this.updateStick(e.clientX, e.clientY);
    });
    this.stickBase.addEventListener('pointermove', (e) => {
      if (e.pointerId !== this.stickPointer) return;
      e.preventDefault();
      this.updateStick(e.clientX, e.clientY);
    });
    const endStick = (e: PointerEvent): void => {
      if (e.pointerId !== this.stickPointer) return;
      this.resetStick();
    };
    this.stickBase.addEventListener('pointerup', endStick);
    this.stickBase.addEventListener('pointercancel', endStick);
  }

  private updateStick(clientX: number, clientY: number): void {
    let dx = clientX - this.stickCx;
    let dy = clientY - this.stickCy;
    const dist = Math.hypot(dx, dy);
    if (dist > this.maxRadius) {
      const k = this.maxRadius / dist;
      dx *= k;
      dy *= k;
    }
    // Move the knob visually.
    this.stickKnob.style.transform = `translate(${dx}px, ${dy}px)`;
    // Normalize to [-1, 1]. Screen-up (negative dy) should move the ship up
    // (analog +Y), matching the keyboard's ArrowUp; screen-right is analog +X.
    const nx = dx / this.maxRadius;
    const ny = -dy / this.maxRadius;
    this.input.setAnalog(nx, ny);
  }

  private resetStick(): void {
    this.stickPointer = null;
    this.stickKnob.style.transform = 'translate(0px, 0px)';
    this.input.clearAnalog();
  }

  get isEnabled(): boolean {
    return this.enabled;
  }
}
