/**
 * Central tuning constants. Adjust these to change game feel.
 */
export const CONFIG = {
  // Play field bounds (world units) the ship can move within.
  bounds: {
    x: 9, // left/right half-extent
    yMin: -5, // bottom
    yMax: 5, // top (reaches the highest enemy row at originY = 4.5)
  },

  player: {
    speed: 12, // units per second
    fireCooldown: 0.22, // seconds between shots
    size: { x: 1.2, y: 1.1, z: 1.2 },
    startLives: 3,
    // Per-level advantage upgrades the player picks after clearing a level.
    upgrades: {
      // Extra speed (world units/sec) added per "increase ship speed" pick.
      speedPerPick: 3,
      // Lateral spacing (world units) between parallel shots when multi-shot.
      shotSpacing: 0.7,
    },
    // Visual guide rig that projects the ship's aim/position onto the grids.
    guideColor: 0xff3344,
    guideOpacity: 0.45,
    // Ring pulse shown on an enemy the aim line is locked onto.
    lockRingColor: 0xff3344,
    lockRingPulse: 1.4, // pulses per second
    lockRingMinRadius: 0.6,
    lockRingMaxRadius: 1.1,
  },

  bullet: {
    playerSpeed: 24, // travels +Z (into the screen, toward enemies)
    enemySpeed: 10, // travels -Z (toward the player)
    size: { x: 0.18, y: 0.18, z: 0.9 },
    maxActive: 128,
    // How strongly enemy projectiles steer toward the ship's X/Y each second.
    // 0 = no homing (straight shots); higher = tighter tracking. Try 1-6.
    enemyHoming: 0.1,
    // Cap on the lateral (X/Y) homing speed so bullets can't teleport sideways.
    enemyHomingMaxSpeed: 8,
  },

  enemies: {
    cols: 8,
    rows: 5,
    spacingX: 1.9,
    spacingY: 1.5,
    layerSpacingZ: 2.2, // depth between stacked enemy layers (incremental levels)
    size: { x: 1.0, y: 1.0, z: 1.0 },
    // Grid lives "in the background" at high Z and advances toward player (-Z).
    startZ: 26,
    originY: 4.5,
    stepInterval: 0.75, // seconds between marches (mayor = avance más pausado)
    stepX: 0.5, // horizontal march distance
    stepZ: 1.1, // forward lunge when hitting an edge (menor = se acerca más despacio)
    edgeX: 7, // horizontal travel limit before dropping forward
    // Continuous vertical bob of the whole formation (moves up/down while it
    // marches sideways). Set bobAmplitude to 0 to disable.
    bobAmplitude: 1.5, // how far up/down the formation travels (world units)
    bobSpeed: 0.14, // oscillations per second (matched to the sideways march speed)
    // --- Invader fire control (how many shots the invaders take) ---
    fireChance: 0.05, // probability each living enemy fires per march step
    maxShotsPerStep: 6, // cap on how many invaders may fire in a single step
    maxActiveShots: 24, // cap on enemy bullets on screen at once (0 = unlimited)
    loseZ: 2, // if any enemy reaches this Z, player loses
    pointsPerKill: 100,
    // Glowing footprint each invader projects onto the dark floor grid, giving
    // a depth cue for how close the fleet is. A plain dark shadow is invisible
    // against the dark arena, so this uses a bright additive marker that
    // intensifies (brighter + tighter) as the invader nears the player.
    shadowColor: 0x46e8ff, // cyan glow that pops on the dark floor
    shadowOpacityFar: 0.14, // opacity when at the fleet's starting depth
    shadowOpacityNear: 0.6, // opacity when right on top of the player
    // Color palette for enemies (incremental levels). The body color is chosen
    // by (row + layer) % palette.length: within one Z layer the rows cycle
    // through these colors (so each row differs), and each deeper Z layer
    // rotates the palette so its set of row-colors looks distinct.
    layerColors: [
      { color: 0x4dff5a, emissive: 0x16c83a }, // green
      { color: 0x3aa6ff, emissive: 0x1466c8 }, // blue
      { color: 0xffe23a, emissive: 0xc8a800 }, // yellow
      { color: 0xff8a2a, emissive: 0xc85a00 }, // orange
      { color: 0xff3ea0, emissive: 0xc81f74 }, // magenta
    ],
  },

  camera: {
    // Behind-the-ship chase view using a perspective camera. The camera sits
    // behind (negative Z) and slightly above the player, looking forward toward
    // the advancing fleet (+Z).
    fov: 60,
    // Aspect ratio the `fov` is tuned for (a typical landscape window). On
    // narrower viewports (portrait phones/tablets) the vertical FOV is widened
    // to preserve this framing's horizontal extent, so the ship's full
    // left/right travel stays visible instead of the camera feeling far away.
    referenceAspect: 16 / 9,
    // Upper clamp on the auto-widened vertical FOV so very tall/narrow viewports
    // don't zoom out absurdly (which would re-introduce the "too far" feel).
    maxFov: 100,
    near: 0.1,
    far: 300,
    position: { x: 0, y: 2.5, z: -12 },
    lookAt: { x: 0, y: 1, z: 16 },
  },

  leaderboard: {
    maxEntries: 10,
    storageKey: 'iso-invaders-leaderboard',
  },

  // Particle burst shown when the player ship is hit by an enemy projectile.
  explosion: {
    particles: 24, // number of debris particles per burst
    particleSize: 0.07, // edge length of each cube particle (world units)
    minSpeed: 6, // slowest particle launch speed (units/sec)
    maxSpeed: 16, // fastest particle launch speed (units/sec)
    drag: 2.2, // velocity damping per second (higher = quicker stop)
    duration: 0.7, // seconds for a burst to fully fade out
    gravity: 9, // downward pull on particles (units/sec^2)
    colors: [0xfff4b0, 0xffe23a, 0xffcc00], // yellow flash -> warm yellow embers
    maxBursts: 6, // simultaneous bursts the pool supports
  },

  // Reference grids that help read the ship's vertical/horizontal position
  // relative to the invader formation.
  playfield: {
    // Span of the battlefield used to size the reference grids. Sized to fully
    // enclose all gameplay: ship X bounds (±9), fleet edge travel + formation
    // width (~±14), vertical ship/fleet range, and depth from in front of the
    // player back to behind the fleet's start.
    width: 32, // total X extent (x: -16..16) — contains ship + fleet sway
    height: 18, // total Y extent (vertical wall height)
    depth: 44, // total Z extent (in front of player .. behind fleet start)
    centerY: -0.75, // vertical midpoint of the wall grid
    floorY: -8, // Y of the horizontal floor grid (below the ship)
    backZ: 32, // Z of the back wall (behind the fleet's start at z=26)
    divisions: 12, // grid cell count along each axis
    color: 0x5a8fd6, // major line color
    subColor: 0x3a5f9a, // minor line color
    opacity: 0.85, // grid line opacity (0..1)
  },

  // Incremental-level scaling. Tuned by imp-dev (issue 005/007); placeholders
  // here only stabilize the type for the test/skeleton phase.
  levels: {
    bonusBase: 500, // level-clear bonus = bonusBase × level
    definedLevels: 5, // number of explicitly defined levels in src/levels/levels.ts
    maxLayers: 5, // cap on enemy depth-layers
    // Per-extra-level scaling applied beyond the defined set (monotonic).
    stepIntervalFactor: 0.95, // multiply stepInterval per extra level (faster)
    stepZFactor: 1.08, // multiply stepZ per extra level (advances faster)
    fireChanceFactor: 1.1, // multiply fireChance per extra level (more fire)
    fireChanceMax: 0.5, // clamp on scaled fireChance
    enemyHomingFactor: 1.12, // multiply enemy-bullet homing per extra level (tighter tracking)
    enemyHomingMax: 6, // clamp on scaled homing strength
  },

  // Background music: MIDI files played (and looped) per level, synthesized in
  // the browser. The playlist cycles across levels (level 1 -> index 0, etc.).
  music: {
    enabled: true,
    volumeDb: -18, // master music volume in decibels (lower = more headroom, less clipping)
    // A brick-wall limiter on the master bus prevents the summed polyphonic
    // tracks from exceeding 0 dBFS and hard-clipping (the harsh saturation).
    limiterThresholdDb: -1,
    // Served from /public/music. Order defines the per-level cycle. Paths are
    // relative (no leading slash) so they resolve under Vite's base URL, which
    // matters for GitHub Pages subpath hosting (e.g. /iso-invaders/).
    playlist: [
      'music/stage-1.mid',
      'music/stage-5.mid',
      'music/stage-8.mid',
    ],
    // Voice of the synthesizer that renders each MIDI note.
    synth: {
      // Oscillator waveform: 'sine' | 'triangle' | 'square' | 'sawtooth'
      // and "fat"/"fm"/"am"/"pulse"/"pwm" variants (e.g. 'fatsawtooth').
      oscillator: 'fatsawtooth',
      // ADSR amplitude envelope (seconds, except sustain which is 0..1).
      // A slightly slower attack/release avoids click transients on note edges.
      envelope: { attack: 0.00, decay: 0.18, sustain: 0.35, release: 0.5 },
      // Max simultaneous voices per track. Too low causes "voice stealing"
      // clicks when dense MIDI passages exceed it.
      maxPolyphony: 64,
    },
    // Post-synth effects chain. Each effect can be toggled and tuned to change
    // the overall feel (e.g. lush reverb, retro delay, warm chorus, grit).
    effects: {
      // Resonant low-pass filter: tames harsh highs / adds warmth.
      filter: { enabled: true, frequency: 4500, type: 'lowpass', Q: 0.7 },
      // Thickens the sound with subtle pitch-modulated voices.
      chorus: { enabled: true, frequency: 1.5, delayTime: 3.5, depth: 0.6, wet: 0.4 },
      // Rhythmic echo synced to the transport.
      delay: { enabled: true, delayTime: '8n', feedback: 0.25, wet: 0.18 },
      // Soft saturation / overdrive for grit.
      distortion: { enabled: false, amount: 0.25, wet: 0.3 },
      // Spatial tail; the last effect before the master gain.
      reverb: { enabled: true, decay: 3.5, preDelay: 0.02, wet: 0.28 },
    },
  },
} as const;

export type Vec3Size = { x: number; y: number; z: number };
