import { CONFIG } from '../config';

export interface LeaderboardEntry {
  initials: string;
  score: number;
  timestamp: number;
}

export class LeaderboardService {
  private readonly storageKey = CONFIG.leaderboard.storageKey;
  private readonly maxEntries = CONFIG.leaderboard.maxEntries;

  qualifies(score: number): boolean {
    if (score <= 0) return false;
    try {
      const entries = this.sort(this.readEntries());
      if (entries.length < this.maxEntries) return true;
      const lowest = entries[entries.length - 1];
      return score > lowest.score;
    } catch {
      return false;
    }
  }

  save(initials: string, score: number): void {
    try {
      const entries = this.readEntries();
      entries.push({ initials, score, timestamp: Date.now() });
      const sorted = this.sort(entries).slice(0, this.maxEntries);
      localStorage.setItem(this.storageKey, JSON.stringify(sorted));
    } catch {
      // Silently no-op
    }
  }

  getAll(): LeaderboardEntry[] {
    try {
      return this.sort(this.readEntries());
    } catch {
      return [];
    }
  }

  isAvailable(): boolean {
    try {
      const testKey = `${this.storageKey}-test`;
      localStorage.setItem(testKey, '1');
      localStorage.removeItem(testKey);
      return true;
    } catch {
      return false;
    }
  }

  private readEntries(): LeaderboardEntry[] {
    const raw = localStorage.getItem(this.storageKey);
    if (!raw) return [];
    return JSON.parse(raw) as LeaderboardEntry[];
  }

  private sort(entries: LeaderboardEntry[]): LeaderboardEntry[] {
    return entries.sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      return b.timestamp - a.timestamp;
    });
  }
}
