import * as THREE from 'three';
import { CONFIG } from '../config';

/**
 * Builds the scene with a perspective camera positioned behind and slightly
 * above the player's ship, looking forward toward the advancing fleet (a
 * behind-the-ship chase view). Returns the scene and camera plus a resize
 * handler that keeps the aspect ratio correct.
 */
export function createScene(aspect: number): {
  scene: THREE.Scene;
  camera: THREE.PerspectiveCamera;
  resize: (aspect: number) => void;
} {
  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x05060f);
  scene.fog = new THREE.FogExp2(0x05060f, 0.018);

  const { fov, near, far, position, lookAt } = CONFIG.camera;
  const camera = new THREE.PerspectiveCamera(fov, aspect, near, far);
  camera.position.set(position.x, position.y, position.z);
  camera.lookAt(lookAt.x, lookAt.y, lookAt.z);
  applyAspectFov(camera, aspect);

  // Lighting: a key directional light plus soft ambient fill.
  const ambient = new THREE.AmbientLight(0x4060ff, 0.6);
  scene.add(ambient);

  const key = new THREE.DirectionalLight(0xffffff, 1.1);
  key.position.set(10, 20, -5);
  scene.add(key);

  const rim = new THREE.PointLight(0x66ccff, 0.8, 80);
  rim.position.set(0, 6, 20);
  scene.add(rim);

  // Reference grids (horizontal floor + vertical back wall) so the player can
  // read the ship's vertical and horizontal position against the invaders.
  scene.add(createReferenceGrids());

  // Starfield backdrop.
  scene.add(createStarfield());

  const resize = (a: number): void => {
    camera.aspect = a;
    applyAspectFov(camera, a);
  };

  return { scene, camera, resize };
}

/**
 * Keeps the player's full range of motion framed regardless of viewport shape.
 *
 * A perspective camera's `fov` is vertical, so on narrow (portrait / mobile)
 * viewports the *horizontal* field of view collapses, pushing the ship to the
 * edges or appearing to shrink the scene. We compensate by holding the
 * horizontal FOV constant at/below a reference (landscape) aspect: when the
 * viewport is narrower than the reference, the vertical FOV is widened so the
 * same world width stays visible. On wide viewports the configured FOV is used
 * as-is (clamped to a sane maximum so we never zoom absurdly far out).
 */
function applyAspectFov(camera: THREE.PerspectiveCamera, aspect: number): void {
  const baseFov = CONFIG.camera.fov; // vertical FOV tuned for landscape
  const refAspect = CONFIG.camera.referenceAspect; // aspect the baseFov is tuned for
  const maxFov = CONFIG.camera.maxFov;

  let fov: number = baseFov;
  if (aspect < refAspect) {
    // Preserve the horizontal FOV from the reference framing. Horizontal FOV
    // h = 2*atan(tan(v/2) * aspect); solve for the vertical FOV that keeps the
    // reference's horizontal extent at the current (narrower) aspect.
    const baseV = THREE.MathUtils.degToRad(baseFov);
    const horiz = 2 * Math.atan(Math.tan(baseV / 2) * refAspect);
    const v = 2 * Math.atan(Math.tan(horiz / 2) / aspect);
    fov = Math.min(maxFov, THREE.MathUtils.radToDeg(v));
  }

  camera.fov = fov;
  camera.updateProjectionMatrix();
}

/**
 * Builds a single combined reference grid shaped like an open box — a floor,
 * ceiling, back wall, and two side walls — all sharing edges so it reads as one
 * continuous enclosure (open toward the player at the front). The shared cell
 * size makes the ship's X/Y position and depth legible against the gridlines.
 */
function createReferenceGrids(): THREE.LineSegments {
  const pf = CONFIG.playfield;
  const cell = pf.width / pf.divisions;

  const halfW = pf.width / 2;
  const floorY = pf.floorY;
  const topY = floorY + pf.height;
  const backZ = pf.backZ;
  const frontZ = backZ - pf.depth;

  const divX = pf.divisions;
  const divY = Math.round(pf.height / cell);
  const divZ = Math.round(pf.depth / cell);

  const positions: number[] = [];
  const colors: number[] = [];
  const major = new THREE.Color(pf.color);
  const minor = new THREE.Color(pf.subColor);

  const line = (
    x1: number,
    y1: number,
    z1: number,
    x2: number,
    y2: number,
    z2: number,
    c: THREE.Color,
  ): void => {
    positions.push(x1, y1, z1, x2, y2, z2);
    colors.push(c.r, c.g, c.b, c.r, c.g, c.b);
  };

  const nearZero = (v: number): boolean => Math.abs(v) < 1e-6;
  const xAt = (i: number): number => -halfW + (i / divX) * pf.width;
  const yAt = (j: number): number => floorY + (j / divY) * pf.height;
  const zAt = (k: number): number => frontZ + (k / divZ) * pf.depth;

  // --- Floor (y = floorY) ---
  for (let i = 0; i <= divX; i++) {
    line(xAt(i), floorY, frontZ, xAt(i), floorY, backZ, nearZero(xAt(i)) ? major : minor);
  }
  for (let k = 0; k <= divZ; k++) {
    line(-halfW, floorY, zAt(k), halfW, floorY, zAt(k), minor);
  }

  // --- Ceiling (y = topY) ---
  for (let i = 0; i <= divX; i++) {
    line(xAt(i), topY, frontZ, xAt(i), topY, backZ, nearZero(xAt(i)) ? major : minor);
  }
  for (let k = 0; k <= divZ; k++) {
    line(-halfW, topY, zAt(k), halfW, topY, zAt(k), minor);
  }

  // --- Back wall (z = backZ) ---
  // Vertical lines (constant X); skip endpoints' duplicate horizontal edges.
  for (let i = 0; i <= divX; i++) {
    line(xAt(i), floorY, backZ, xAt(i), topY, backZ, nearZero(xAt(i)) ? major : minor);
  }
  // Horizontal lines (constant Y); skip j=0 (floor back edge) and j=divY
  // (ceiling back edge) — already drawn by floor/ceiling.
  for (let j = 1; j < divY; j++) {
    line(-halfW, yAt(j), backZ, halfW, yAt(j), backZ, minor);
  }

  // --- Side walls (x = -halfW and x = +halfW) ---
  for (const sx of [-halfW, halfW]) {
    // Vertical lines (constant Z); skip z=backZ (shared with back wall).
    for (let k = 0; k < divZ; k++) {
      line(sx, floorY, zAt(k), sx, topY, zAt(k), minor);
    }
    // Depth lines (constant Y); skip j=0 (floor side edge) and j=divY
    // (ceiling side edge) — already drawn by floor/ceiling.
    for (let j = 1; j < divY; j++) {
      line(sx, yAt(j), frontZ, sx, yAt(j), backZ, minor);
    }
  }

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute(
    'position',
    new THREE.Float32BufferAttribute(positions, 3),
  );
  geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  const material = new THREE.LineBasicMaterial({
    vertexColors: true,
    transparent: true,
    opacity: pf.opacity,
  });
  return new THREE.LineSegments(geometry, material);
}

function createStarfield(): THREE.Points {
  const count = 600;
  const positions = new Float32Array(count * 3);
  for (let i = 0; i < count; i++) {
    positions[i * 3] = (Math.random() - 0.5) * 120;
    positions[i * 3 + 1] = (Math.random() - 0.5) * 80;
    positions[i * 3 + 2] = (Math.random() - 0.5) * 120 + 30;
  }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  const material = new THREE.PointsMaterial({
    color: 0x88aaff,
    size: 0.25,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.8,
  });
  return new THREE.Points(geometry, material);
}
