import * as THREE from 'three';
import { CONFIG } from '../config';

/**
 * Classic Space Invaders alien sprites as pixel bitmaps. Each row is a string;
 * '1' = a filled pixel (a voxel cube), anything else = empty. There are FIVE
 * distinct invader shapes (matching the five reference aliens) so adjacent grid
 * rows never repeat the same type. Each alien has TWO frames that alternate
 * every march step (the classic "walk" animation).
 */

// 1) SQUID — tall, two antennae, narrow body (yellow).
