import * as THREE from 'three';
import { CONFIG } from '../config';
import { InputManager } from '../systems/InputManager';
import { makeAABB, type AABB } from '../systems/CollisionSystem';
import { buildPlayerShip } from './buildPlayerShip';

export class Player {
  /** Root object for the voxel fighter; positioned/scaled like the old mesh. */
  readonly mesh: THREE.Group;
  /** Guide lines that project the ship's aim and ground position. */
  readonly guides = new THREE.Group();
  private aimLine!: THREE.Line;
  private dropLine!: THREE.Line;
  private cooldown = 0;
  private enginePulse = 0;
  private readonly engineGlow: THREE.Mesh[];
  /** Current movement speed (units/sec); raised by speed upgrades. */
  speed: number = CONFIG.player.speed;

  constructor() {
    const { x, y, z } = CONFIG.player.size;
    // An 8-bit voxel-style fighter jet (boxy blocks), facing +Z (toward enemies).
    const built = buildPlayerShip();
    this.mesh = built.group;
    this.engineGlow = built.engineGlow;
    // The ship is modeled in a ~unit box; scale it to the configured footprint.
    this.mesh.scale.set(x, y, z);
    this.buildGuides();
    this.reset();
  }

  /**
   * Builds two guide lines that make the ship's position readable against the
   * reference grids:
   *  - an **aim line** projecting forward (+Z) at the ship's exact X/Y, so you
   *    can see which invader column/row you're lined up with;
   *  - a **drop line** falling straight down to the floor grid, anchoring the
   *    ship's horizontal position and depth.
   */
  private buildGuides(): void {
    const lineMat = new THREE.LineBasicMaterial({
      color: CONFIG.player.guideColor,
      transparent: true,
      opacity: CONFIG.player.guideOpacity,
    });

    const aimGeo = new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(0, 0, 0),
      new THREE.Vector3(0, 0, CONFIG.enemies.startZ),
    ]);
    this.aimLine = new THREE.Line(aimGeo, lineMat);

    const dropGeo = new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(0, 0, 0),
      new THREE.Vector3(0, -1, 0),
    ]);
    this.dropLine = new THREE.Line(dropGeo, lineMat.clone());

    this.guides.add(this.aimLine, this.dropLine);
  }

  private syncGuides(): void {
    const pos = this.mesh.position;
    // Aim line starts at the ship and runs forward toward the fleet.
    this.aimLine.position.set(pos.x, pos.y, pos.z);
    // Drop line falls from the ship to the floor grid plane.
    this.dropLine.position.set(pos.x, pos.y, pos.z);
    const depth = pos.y - CONFIG.playfield.floorY;
    this.dropLine.scale.set(1, Math.max(depth, 0.001), 1);
  }

  reset(): void {
    this.mesh.position.set(0, CONFIG.bounds.yMin + 1, 0);
    this.cooldown = 0;
    this.syncGuides();
  }

  update(dt: number, input: InputManager): boolean {
    const speed = this.speed;
    // The chase camera looks toward +Z (from behind the ship), which mirrors
    // the X axis on screen: world +X renders on the left. Negate horizontal
    // input so pressing Right/D moves the ship right *as seen on screen*.
    const moveX = -input.moveX;
    this.mesh.position.x += moveX * speed * dt;
    this.mesh.position.y += input.moveY * speed * dt;

    const b = CONFIG.bounds;
    this.mesh.position.x = clamp(this.mesh.position.x, -b.x, b.x);
    this.mesh.position.y = clamp(this.mesh.position.y, b.yMin, b.yMax);

    if (this.cooldown > 0) this.cooldown -= dt;

    // Bank the ship slightly when moving for a touch of arcade juice.
    this.mesh.rotation.z = -moveX * 0.3;
    // Slight pitch up/down when moving vertically.
    this.mesh.rotation.x = -input.moveY * 0.15;

    // Pulse the engine exhaust glow.
    this.enginePulse += dt * 12;
    const glow = 0.7 + 0.3 * Math.sin(this.enginePulse);
    for (const e of this.engineGlow) e.scale.setScalar(glow);

    this.syncGuides();

    if ((input.consumeFire() || input.fireHeld) && this.cooldown <= 0) {
      this.cooldown = CONFIG.player.fireCooldown;
      return true; // signal the game to spawn a bullet
    }
    return false;
  }

  get muzzlePosition(): { x: number; y: number; z: number } {
    return {
      x: this.mesh.position.x,
      y: this.mesh.position.y,
      z: this.mesh.position.z + CONFIG.player.size.z,
    };
  }

  /**
   * Returns `count` evenly-spaced muzzle positions across the ship's width,
   * centered on the ship, for multi-shot firing. `count` of 1 returns just the
   * center muzzle.
   */
  muzzlePositions(
    count: number,
    spacing: number,
  ): Array<{ x: number; y: number; z: number }> {
    const base = this.muzzlePosition;
    if (count <= 1) return [base];
    const positions: Array<{ x: number; y: number; z: number }> = [];
    const offset = ((count - 1) * spacing) / 2;
    for (let i = 0; i < count; i++) {
      positions.push({ x: base.x - offset + i * spacing, y: base.y, z: base.z });
    }
    return positions;
  }

  get aabb(): AABB {
    return makeAABB(this.mesh.position, CONFIG.player.size);
  }
}

function clamp(v: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, v));
}
